arguments.new_str:
using Microsoft.ML;
using Microsoft.ML.Data;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddPredictionEnginePool<ChurnInput, ChurnPrediction>()
    .FromFile(Path.Combine(AppContext.BaseDirectory, "Data", "ChurnModel.zip"));

var app = builder.Build();

// Train the model at startup if it doesn't exist
var modelPath = Path.Combine(AppContext.BaseDirectory, "Data", "ChurnModel.zip");
if (!File.Exists(modelPath))
{
    TrainModel(Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv"), modelPath);
}

app.MapGet("/", () => "Churn Predictor API — POST to /predict");

app.MapPost("/predict", (ChurnInput input, PredictionEnginePool<ChurnInput, ChurnPrediction> pool) =>
{
    var prediction = pool.Predict(input);
    return Results.Ok(new
    {
        WillChurn = prediction.PredictedLabel,
        Probability = prediction.Probability,
        Score = prediction.Score,
    });
});

app.MapPost("/train", () =>
{
    var csvPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
    TrainModel(csvPath, modelPath);
    return Results.Ok("Model retrained successfully.");
});

app.Run();

static void TrainModel(string csvPath, string modelPath)
{
    var mlContext = new MLContext(seed: 42);

    IDataView data = mlContext.Data.LoadFromTextFile<ChurnInput>(
        csvPath, hasHeader: true, separatorChar: ',');

    var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2);

    var pipeline = mlContext.Transforms.Categorical
        .OneHotEncoding("RegionEncoded", nameof(ChurnInput.Region))
        .Append(mlContext.Transforms.Concatenate("Features",
            nameof(ChurnInput.Age),
            nameof(ChurnInput.Income),
            "RegionEncoded",
            nameof(ChurnInput.PurchaseHistory)))
        .Append(mlContext.Transforms.NormalizeMinMax("Features"))
        .Append(mlContext.BinaryClassification.Trainers
            .SdcaLogisticRegression(
                labelColumnName: "Label",
                featureColumnName: "Features"))
        .Append(mlContext.Transforms.CopyColumns("PredictedLabel", "PredictedLabel"));

    // Map "Yes"/"No" to boolean label before the pipeline
    var labelPipeline = mlContext.Transforms.CustomMapping<ChurnInput, ChurnLabelMapped>(
            (input, output) => output.Label = input.Churned == "Yes",
            contractName: "ChurnLabelMapping")
        .Append(pipeline);

    var model = labelPipeline.Fit(split.TrainSet);

    var predictions = model.Transform(split.TestSet);
    var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");

    Console.WriteLine($"Accuracy: {metrics.Accuracy:F4}");
    Console.WriteLine($"AUC:      {metrics.AreaUnderRocCurve:F4}");
    Console.WriteLine($"F1 Score: {metrics.F1Score:F4}");

    Directory.CreateDirectory(Path.GetDirectoryName(modelPath)!);
    mlContext.Model.Save(model, data.Schema, modelPath);
    Console.WriteLine($"Model saved to {modelPath}");
}

public class ChurnInput
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = "";
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4)] public string Churned { get; set; } = "";
}

[Microsoft.ML.Data.FunctionName("ChurnLabelMapping")]
public class ChurnLabelMapped
{
    public bool Label { get; set; }
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public bool PredictedLabel { get; set; }
    public float Probability { get; set; }
    public float Score { get; set; }
}

