 static void TrainModel(string csvPath, string modelPath)
 {
     var mlContext = new MLContext(seed: 42);

     IDataView data = mlContext.Data.LoadFromTextFile<ChurnInput>(
         csvPath, hasHeader: true, separatorChar: ',');

     var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2);

     var pipeline = mlContext.Transforms.Categorical
         .OneHotEncoding("RegionEncoded", nameof(ChurnInput.Region))
         .Append(mlContext.Transforms.Concatenate("Features",
             nameof(ChurnInput.Age),
             nameof(ChurnInput.Income),
             "RegionEncoded",
             nameof(ChurnInput.PurchaseHistory)))
         .Append(mlContext.Transforms.NormalizeMinMax("Features"))
         .Append(mlContext.BinaryClassification.Trainers
             .SdcaLogisticRegression(
                 labelColumnName: "Label",
                 featureColumnName: "Features"))
         .Append(mlContext.Transforms.CopyColumns("PredictedLabel", "PredictedLabel"));

     // Map "Yes"/"No" string to boolean Label column
     var labelKeys = new[] { new KeyValuePair<string, bool>("Yes", true), new KeyValuePair<string, bool>("No", false) };
     var labelLookup = mlContext.Transforms.Conversion.MapValue(
         "Label", labelKeys, inputColumnName: nameof(ChurnInput.Churned));
     var labelPipeline = labelLookup.Append(pipeline);

     var model = labelPipeline.Fit(split.TrainSet);

     var predictions = model.Transform(split.TestSet);
     try
     {
         var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
         Console.WriteLine($"Accuracy: {metrics.Accuracy:F4}");
         Console.WriteLine($"AUC:      {metrics.AreaUnderRocCurve:F4}");
         Console.WriteLine($"F1 Score: {metrics.F1Score:F4}");
     }
     catch (ArgumentOutOfRangeException)
     {
         Console.WriteLine("Warning: Test set too small for reliable metrics (need both classes represented).");
     }

     Directory.CreateDirectory(Path.GetDirectoryName(modelPath)!);
     mlContext.Model.Save(model, data.Schema, modelPath);
     Console.WriteLine($"Model saved to {modelPath}");
 }

